  let skipped = 0;
  
  for (let i = 0; i < asignaciones.length; i += 50) {
    const batch = asignaciones.slice(i, i + 50).map(a => {
      const capId = capIdMap[a.nombre_cap];
      if (!capId) { skipped++; return null; }
      return {
        emp_clave: a.emp_clave,
        cap_id: capId,
        completado: true,
        cap_eliminada: false,
        nombre_cap_snap: a.nombre_cap,
        mes: a.anio ? String(a.anio) : null,
        calificacion: a.calificacion,
      };
    }).filter(Boolean);
    
    if (batch.length === 0) continue;
    const { error } = await supabase.from("asignaciones_cap").insert(batch);
    if (error) {
      console.error(`Error asig batch ${i}:`, error.message);
    } else {
      console.log(`  Asignaciones ${i + 1}-${Math.min(i + 50, asignaciones.length)} OK`);
    }
  }
